const body = $input.first().json.body || $input.first().json;

return [{
  json: {
    customer_id:      body.customer_id  || body.policy_holder || `CLM-${Date.now()}`,
    policy_id:        body.policy_id    || '',
    claim_type:       body.type         || body.claim_type || 'Unbekannt',
    claim_amount_chf: parseFloat(body.amount || body.claim_amount || 0),
    description:      body.description  || body.notes || '',
    incident_date:    body.incident_date|| new Date().toISOString().split('T')[0],
    documents:        body.documents    || [],
    channel:          body.channel      || 'web',
    received_at:      new Date().toISOString()
  }
}];

const agent = $input.first().json;
const claim = $('Normalize Claim Data').first().json;

const fraudScore    = agent.fraud_score     || 0;
const confidence    = agent.confidence      || 0.5;
const claimAmount   = claim.claim_amount_chf || 0;
const previousClaims = agent.previous_claims || 0;

// Business rules
let route, urgency;

if (fraudScore > 0.7) {
  route   = 'escalation';
  urgency = 'high';
} else if (claimAmount > 50000 || confidence < 0.65 || previousClaims > 1) {
  route   = 'human_review';
  urgency = claimAmount > 80000 ? 'high' : 'medium';
} else {
  route   = 'automation';
  urgency = 'low';
}

return [{
  json: {
    ...claim,
    classification:  agent.classification  || claim.claim_type,
    priority:        agent.priority        || urgency,
    fraud_score:     fraudScore,
    confidence:      confidence,
    previous_claims: previousClaims,
    route:           route,
    urgency:         urgency,
    title:  `Claim ${claim.claim_type} — CHF ${claimAmount.toLocaleString('de-CH')}`,
    detail: `${agent.classification || claim.claim_type} · Priorität: ${urgency}${
      fraudScore > 0.5 ? ` · Fraud: ${(fraudScore*100).toFixed(0)}%` : ''
    }`,
    agent_latency_ms: agent.latency_ms || null
  }
}];
